  1	import * as React from "react";
  2	import {
  3	  FormGroup,
  4	  MenuToggle,
  5	  MenuToggleElement,
  6	  Select,
  7	  SelectList,
  8	  SelectOption,
  9	  Divider,
 10	  HelperTextItem,
 11	  HelperText,
 12	  FormHelperText,
 13	} from "@patternfly/react-core";
 14	import { useField, useFormikContext } from "formik";
 15	import { getFieldId } from "../../../../copiedFromConsole/formik-fields/field-utils";
 16	import { useNodeHealthCheckTranslation } from "../../../../localization/useNodeHealthCheckTranslation";
 17	import {
 18	  PREDEFINED_REMEDIATION_TEMPLATE_KINDS,
 19	  getKindInfo,
 20	} from "../../../../data/remediationTemplateKinds";
 21	import { getApiVersion } from "../../../../data/model";
 22	import CustomKindModal from "./CustomKindModal";
 23	
 24	interface RemediationTemplateKindFieldProps {
 25	  fieldName: string;
 26	}
 27	
 28	const USE_CUSTOM_KIND = "use-custom-kind";
 29	
 30	export const RemediationTemplateKindField: React.FC<
 31	  RemediationTemplateKindFieldProps
 32	> = ({ fieldName }) => {
 33	  const { t } = useNodeHealthCheckTranslation();
 34	  const { setFieldValue } = useFormikContext();
 35	  const kindFieldName = `${fieldName}.template.kind`;
 36	  const apiVersionFieldName = `${fieldName}.template.apiVersion`;
 37	  const [field, , { setValue }] = useField<string>(kindFieldName);
 38	  const [isOpen, setIsOpen] = React.useState(false);
 39	  const [customKindModalOpen, setCustomKindModalOpen] =
 40	    React.useState<boolean>(false);
 41	  const fieldId = getFieldId(fieldName, "kind");
 42	
 43	  const onToggle = () => {
 44	    setIsOpen(!isOpen);
 45	  };
 46	
 47	  const onSelect = (
 48	    _event: React.MouseEvent<Element, MouseEvent> | undefined,
 49	    value: string | number | undefined
 50	  ) => {
 51	    if (value === USE_CUSTOM_KIND) {
 52	      // Don't set the value, just open the modal
 53	      setCustomKindModalOpen(true);
 54	      setIsOpen(false);
 55	    } else if (value && value !== USE_CUSTOM_KIND) {
 56	      const kind = String(value);
 57	      setValue(kind);
 58	      // Set apiVersion for predefined kinds
 59	      const kindInfo = getKindInfo(kind);
 60	      if (kindInfo) {
 61	        setFieldValue(
 62	          apiVersionFieldName,
 63	          getApiVersion(kindInfo.groupVersionKind)
 64	        );
 65	      }
 66	      setIsOpen(false);
 67	    }
 68	  };
 69	
 70	  return (
 71	    <>
 72	      <FormGroup fieldId={fieldId} label={t("Kind")} isRequired>
 73	        <Select
 74	          id={fieldId}
 75	          isOpen={isOpen}
 76	          selected={field.value}
 77	          onSelect={onSelect}
 78	          onOpenChange={setIsOpen}
 79	          toggle={(toggleRef: React.Ref<MenuToggleElement>) => (
 80	            <MenuToggle
 81	              ref={toggleRef}
 82	              onClick={onToggle}
 83	              isExpanded={isOpen}
 84	              isFullWidth
 85	            >
 86	              {field.value || ""}
 87	            </MenuToggle>
 88	          )}
 89	          maxMenuHeight="25rem"
 90	          isScrollable
 91	        >
 92	          <SelectList id={`${fieldId}-listbox`}>
 93	            {PREDEFINED_REMEDIATION_TEMPLATE_KINDS.map((kind) => {
 94	              const kindInfo = getKindInfo(kind);
 95	              const apiVersion = kindInfo
 96	                ? getApiVersion(kindInfo.groupVersionKind)
 97	                : undefined;
 98	              return (
 99	                <SelectOption key={kind} value={kind} description={apiVersion}>
100	                  {kind}
101	                </SelectOption>
102	              );
103	            })}
104	            <Divider key="kind-field-separator" component="li" />
105	            <SelectOption key={USE_CUSTOM_KIND} value={USE_CUSTOM_KIND}>
106	              {t("Use custom kind")}
107	            </SelectOption>
108	          </SelectList>
109	        </Select>
110	        <FormHelperText>
111	          <HelperText>
112	            <HelperTextItem>
113	              {t(
114	                "Choose from officially supported remediation templates, or use a custom kind."
115	              )}
116	            </HelperTextItem>
117	          </HelperText>
118	        </FormHelperText>
119	      </FormGroup>
120	      {customKindModalOpen && (
121	        <CustomKindModal
122	          fieldName={`${fieldName}.template`}
123	          onClose={() => setCustomKindModalOpen(false)}
124	        />
125	      )}
126	    </>
127	  );
128	};

